3: type TokenType =
4:   | "IDENT"
5:   | "NUMBER"
6:   | "LT"
7:   | "GT"
8:   | "LPAREN"
9:   | "RPAREN"
10:   | "PLUS"
11:   | "COLON"
12:   | "ASSIGN"
13:   | "SEMICOLON";
