20: function tokenize(source: string): Token[] {
21:   const tokens: Token[] = [];
22:   let i = 0;
23:   while (i < source.length) {
24:     const ch = source[i]!;
25:     if (/\s/.test(ch)) {
26:       i++;
27:       continue;
28:     }
29:     if (ch === "<") {
30:       tokens.push({ type: "LT", value: "<" });
31:       i++;
32:     } else if (ch === ">") {
33:       tokens.push({ type: "GT", value: ">" });
34:       i++;
35:     } else if (ch === "(") {
36:       tokens.push({ type: "LPAREN", value: "(" });
37:       i++;
38:     } else if (ch === ")") {
39:       tokens.push({ type: "RPAREN", value: ")" });
40:       i++;
41:     } else if (ch === "+") {
42:       tokens.push({ type: "PLUS", value: "+" });
43:       i++;
44:     } else if (ch === ":") {
45:       tokens.push({ type: "COLON", value: ":" });
46:       i++;
47:     } else if (ch === "=") {
48:       tokens.push({ type: "ASSIGN", value: "=" });
49:       i++;
50:     } else if (ch === ";") {
51:       tokens.push({ type: "SEMICOLON", value: ";" });
52:       i++;
53:     } else if (/[a-zA-Z_]\w*/.test(ch)) {
54:       let ident = "";
55:       while (i < source.length && /\w/.test(source[i]!)) {
56:         ident += source[i]!;
57:         i++;
58:       }
59:       tokens.push({ type: "IDENT", value: ident });
60:     } else if (/[0-9]/.test(ch)) {
61:       let num = "";
62:       while (i < source.length && /[0-9]/.test(source[i]!)) {
63:         num += source[i]!;
64:         i++;
65:       }
66:       tokens.push({ type: "NUMBER", value: num });
67:     } else {
68:       throw new Error(`Unexpected character '${ch}' at position ${i}`);
69:     }
70:   }
71:   return tokens;
72: }
