74: // --- AST nodes ---
75: 
76: type Expr = ReadExpr | NumberLit | BinOp | IdentRef;
77: 
78: interface ReadExpr {
79:   kind: "read";
80:   typeArg: string; // e.g. "U8", "I32"
81: }
82: 
83: interface NumberLit {
84:   kind: "number";
85:   value: number;
86: }
87: 
88: interface BinOp {
89:   kind: "binop";
90:   op: "+";
91:   left: Expr;
92:   right: Expr;
93: }
94: 
95: interface IdentRef {
96:   kind: "ident";
97:   name: string;
98: }
