114: // --- Recursive descent parser ---
115: 
116: class Parser {
117:   private pos = 0;
118: 
119:   constructor(private tokens: Token[]) {}
120: 
121:   parseProgram(): Statement[] | null {
122:     if (this.tokens.length === 0) return [];
123:     const stmts: Statement[] = [];
124:     while (!this.atEnd()) {
125:       stmts.push(this.parseStatement());
126:     }
127:     return stmts;
128:   }
129: 
130:   private atEnd(): boolean {
131:     return this.pos >= this.tokens.length;
132:   }
133: 
134:   private parseStatement(): Statement {
135:     const tok = this.peek();
136: 
137:     // let x : Type = expr ;
138:     if (tok.type === "IDENT" && tok.value === "let") {
139:       return this.parseLetDecl();
140:     }
141: 
142:     const expr = this.parseExpression();
143:     // If followed by ';', consume it — otherwise leave it for next iteration (end of program)
144:     if (!this.atEnd() && this.peek().type === "SEMICOLON") {
145:       this.advance();
146:     }
147:     return { kind: "expr", expr };
148:   }
149: 
150:   private parseLetDecl(): LetDecl {
151:     // consume 'let'
152:     this.advance();
153: 
154:     // variable name (IDENT)
155:     const nameTok = this.expect("IDENT");
156:     if (nameTok.type !== "IDENT")
157:       throw new Error(
158:         `Expected identifier after 'let', got '${nameTok.value}'`,
159:       );
160:     const name = nameTok.value;
161: 
162:     // ':' type annotation
163:     this.expect("COLON", `':' after variable name '${name}'`);
164: 
165:     // type argument (e.g. U8) — read until '=' or ';'
166:     let typeAnnotation = "";
167:     while (!this.atEnd() && !["ASSIGN"].includes(this.peek().type)) {
168:       const t = this.advance();
169:       if (t.type === "GT") break;
170:       typeAnnotation += t.value;
171:     }
172: 
173:     // '=' initializer expression
174:     this.expect("ASSIGN", `'=' after type annotation`);
175:     const init = this.parseExpression();
176: 
177:     // ';' terminator
178:     this.expect("SEMICOLON", `';' at end of let declaration for '${name}'`);
179: 
180:     return { kind: "let", name, typeAnnotation, init };
181:   }
182: 
183:   private parseExpression(): Expr {
184:     let left = this.parsePrimary();
185: 
186:     while (!this.atEnd() && this.peek().type === "PLUS") {
187:       this.advance(); // consume '+'
188:       const right = this.parsePrimary();
189:       left = { kind: "binop", op: "+", left, right };
190:     }
191: 
192:     return left;
193:   }
194: 
195:   private parsePrimary(): Expr {
196:     const tok = this.peek();
197: 
198:     // Parenthesized expression
199:     if (tok.type === "LPAREN") {
200:       this.advance(); // consume '('
201:       const expr = this.parseExpression();
202:       this.expect("RPAREN", "')'");
203:       return expr;
204:     }
205: 
206:     // read<T>()
207:     if (tok.type === "IDENT" && tok.value === "read") {
208:       this.advance(); // consume 'read'
209:       const typeArg = this.parseTypeArgument();
210:       this.expect("LPAREN", `'(' after read<T>`);
211:       this.expect("RPAREN", "')' in read expression");
212:       return { kind: "read", typeArg };
213:     }
214: 
215:     // number literal
216:     if (tok.type === "NUMBER") {
217:       this.advance();
218:       return { kind: "number", value: parseInt(tok.value, 10) };
219:     }
220: 
221:     // identifier reference — but NOT keywords like 'let' or 'read' followed by '<'
222:     if (tok.type === "IDENT" && tok.value !== "let") {
223:       this.advance();
224:       return { kind: "ident", name: tok.value };
225:     }
226: 
227:     throw new Error(`Unexpected token '${tok.value}'`);
228:   }
229: 
230:   private parseTypeArgument(): string {
231:     this.expect("LT", `'<', after 'read'`);
232:     let typeArg = "";
233:     while (!this.atEnd() && this.peek().type !== "GT") {
234:       const t = this.advance();
235:       typeArg += t.value;
236:     }
237:     this.expect("GT", `">' in read expression"`);
238:     return typeArg;
239:   }
