241:   private peek(): Token {
242:     if (this.atEnd()) throw new Error("Unexpected end of input");
243:     return this.tokens[this.pos]!;
244:   }
245: 
246:   private advance(): Token {
247:     const tok = this.peek();
248:     this.pos++;
249:     return tok;
250:   }
