252:   // Single consolidated expect method — replaces both old expectToken and expect
253:   private expect(type: TokenType, message?: string): Token {
254:     const tok = this.advance();
255:     if (tok.type !== type) {
256:       throw new Error(
257:         `Expected '${type}' but got '${tok.value}'. ${message ?? ""}`.trim(),
258:       );
259:     }
260:     return tok;
261:   }
