264: // --- Code generation with stdin token index tracking and variable scoping ---
265: 
266: class Generator {
267:   private readIndex = 0; // tracks which stdin token each read<T>() consumes
268:   private declaredVars: Set<string> = new Set();
269: 
270:   generate(statements: Statement[] | null): string {
271:     if (!statements || statements.length === 0) return "return 0";
272: 
273:     const lines: string[] = [];
274:     lines.push("const tokens = stdIn.trim().split(/\\s+/);");
275: 
276:     // First pass: collect declared variable names for name resolution
277:     this.collectDeclarations(statements);
278: 
279:     // Second pass: generate code with name checking
280:     const lastStmt = statements[statements.length - 1]!;
281:     const priorStmts = statements.slice(0, statements.length - 1);
282: 
283:     for (const stmt of priorStmts) {
284:       this.generateStatement(stmt, lines);
285:     }
286: 
287:     // The final statement's expression is returned as the exit code
288:     if (lastStmt.kind === "expr") {
289:       const exprCode = this.generateExpr(lastStmt.expr);
290:       lines.push(`return ${exprCode};`);
291:     } else {
292:       // last stmt was a let decl with trailing ; — nothing to return, default 0
293:       lines.push("return 0;");
294:     }
295: 
296:     return lines.join("\n");
297:   }
298: 
299:   private collectDeclarations(statements: Statement[]): void {
300:     for (const stmt of statements) {
301:       if (stmt.kind === "let") {
302:         this.declaredVars.add(stmt.name);
303:       }
304:     }
305:   }
306: 
307:   private generateStatement(stmt: Statement, lines: string[]): void {
308:     switch (stmt.kind) {
309:       case "let": {
310:         const initCode = this.generateExpr(stmt.init);
311:         lines.push(`const ${stmt.name} = ${initCode};`);
312:         break;
313:       }
314:       case "expr": {
315:         // expression statement executed for side effects only — still need to evaluate reads
316:         this.generateExpr(stmt.expr);
317:         break;
318:       }
319:     }
320:   }
321: 
322:   private generateExpr(node: Expr): string {
323:     switch (node.kind) {
324:       case "read":
325:         return this.generateRead(node);
326:       case "number":
327:         return String(node.value);
328:       case "binop":
329:         return `(${this.generateExpr(
330:           node.left,
331:         )} ${node.op} ${this.generateExpr(node.right)})`;
332:       case "ident": {
333:         if (!this.declaredVars.has(node.name)) {
334:           throw new Error(`Undefined variable '${node.name}'`);
335:         }
336:         return node.name;
337:       }
338:     }
339:   }
340: 
341:   private generateRead(node: ReadExpr): string {
342:     const idx = this.readIndex++;
343:     let parseFn: string;
344:     switch (node.typeArg) {
345:       case "U8":
346:         parseFn = `(Math.floor(Number(tokens[${idx}])) & 0xFF)`;
347:         break;
348:       case "I8":
349:         parseFn = `((Math.floor(Number(tokens[${idx}])) + 128) % 256 - 128)`;
350:         break;
351:       case "U16":
352:         parseFn = `(Math.floor(Number(tokens[${idx}])) & 0xFFFF)`;
353:         break;
354:       case "I16":
355:         parseFn = `((Math.floor(Number(tokens[${idx}])) + 32768) % 65536 - 32768)`;
356:         break;
357:       case "U32":
358:         parseFn = `(Math.trunc(Number(tokens[${idx}])) >>> 0)`;
359:         break;
360:       case "I32":
361:         parseFn = `(Math.trunc(Number(tokens[${idx}])) | 0)`;
362:         break;
363:       default:
364:         throw new Error(`Unsupported read type '${node.typeArg}'`);
365:     }
366:     return parseFn;
367:   }
368: }
