370: export function compileTuffToTS(tuffSourceCode: string): string {
371:   const trimmed = tuffSourceCode.trim();
372:   if (!trimmed) return "return 0";
373:   const tokens = tokenize(trimmed);
374:   const parser = new Parser(tokens);
375:   const statements = parser.parseProgram();
376:   const gen = new Generator();
377:   return gen.generate(statements);
378: }
